#include <stdio.h>
#include <math.h>

long long gcd(long long a, long long b) {
    if (b == 0)
        return a;
    return gcd(b, a % b);
}

long long phi(long long n) {
    long long result = n;
    for (long long i = 2; i * i <= n; i++) {
        if (n % i == 0) {
            while (n % i == 0)
                n /= i;
            result -= result / i;
        }
    }
    if (n > 1)
        result -= result / n;
    return result;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int m;
        scanf("%d", &m);
        long long N = 1;
        for (int i = 0; i < m; i++) {
            long long p, k;
            scanf("%lld %lld", &p, &k);
            N *= pow(p, k);
        }
        int X = 0;
        while (N > 1) {
            N = phi(N);
            X++;
        }
        printf("%d\n", X);
    }
    return 0;
}

