import math
import sys

def gcd(a, b):
    if b == 0:
        return a
    return gcd(b, a % b)

def phi(n):
    result = n
    for i in range(2, int(math.sqrt(n)) + 1):
        if n % i == 0:
            while n % i == 0:
                n //= i
            result -= result // i
    if n > 1:
        result -= result // n
    return result

